{"code": "import urllib.request
import json

def fetch_readme(repo):
    url = f"https://raw.githubusercontent.com/{repo}/main/README.md"
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "Hermes-GitHubHunter"})
        with urllib.request.urlopen(req, timeout=30) as resp:
            return resp.read().decode()
    except Exception as e:
        return None

def extract_patterns(readme, repo_name):
    patterns = []
    if not readme:
        return patterns

    # 提取关键模式（简版）
    if "self-improve" in readme.lower() or "learning" in readme.lower():
        patterns.append({"type": "self-improvement", "found": True})
    if "memory" in readme.lower():
        patterns.append({"type": "memory-architecture", "found": True})
    if "multi" in readme.lower() and "agent" in readme.lower():
        patterns.append({"type": "multi-agent", "found": True})
    if "skill" in readme.lower():
        patterns.append({"type": "skill-extensibility", "found": True})

    return patterns

# 对前 5 个趋势项目提取 README 和模式
repos = [
    "NousResearch/hermes-agent",
    "letta-ai/letta", 
    "aden-hive/hive",
    "MervinPraison/PraisonAI",
    "cline/cline"
]

for repo in repos:
    readme = fetch_readme(repo)
    patterns = extract_patterns(readme, repo)
    print(f"=== {repo} ===")
    print(f"Patterns: {json.dumps(patterns, ensure_ascii=False)}")
    if readme:
        print(f"Readme length: {len(readme)} chars")
