def check_clash():
    try:
        # Clash API 通常监听 7890/7891 或 9090
        ports = [7890, 7891, 9090]
        for port in ports:
            try:
                req = urllib.request.Request(f"http://127.0.0.1:{port}/version")
                req.add_header("User-Agent", "Hermes-ClashChecker")
                with urllib.request.urlopen(req, timeout=3) as resp:
                    data = json.loads(resp.read().decode())
                    return {"status": "running", "version": data, "port": port}
            except:
                continue
        return {"status": "not_responding", "message": "Clash service not responding on common ports"}
    except Exception as e:
        return {"status": "error", "error": str(e)}

result = check_clash()
print(json.dumps(result, indent=2, ensure_ascii=False))
"}

